1	#include "ds4_kvstore.h"
2	
3	/* Shared disk KV checkpoint file support.
4	 *
5	 * The low-level file layout and payload helpers are intentionally shared.  The
6	 * ds4-server still owns the automatic byte-prefix cache policy built on top of
7	 * this file; ds4-agent uses only the same durable format for explicit sessions,
8	 * with its own policy in ds4_agent.c.  Protocol-specific extras, such as the
9	 * server's tool-id -> exact DSML trailer, are attached through trailer hooks and
10	 * still live with the protocol code that owns those mappings. */
11	
12	#include <ctype.h>
13	#include <dirent.h>
14	#include <errno.h>
15	#include <math.h>
16	#include <stdarg.h>
17	#include <stdio.h>
18	#include <stdlib.h>
19	#include <string.h>
20	#include <sys/stat.h>
21	#include <sys/types.h>
22	#include <time.h>
23	#include <unistd.h>
24	
25	#define KV_CACHE_MAGIC0 'K'
26	#define KV_CACHE_MAGIC1 'V'
27	#define KV_CACHE_MAGIC2 'C'
28	#define KV_CACHE_VERSION 1u
29	/* Header byte 20 carries the graph-payload ABI.  It is separate from the outer
30	 * file version because the KVC envelope can remain stable while the serialized
31	 * ds4_session internals become unsafe to restore across runtime changes. */
32	#define KV_CACHE_PAYLOAD_ABI 2u
33	#define KV_CACHE_DEFAULT_MIN_TOKENS 512
34	#define KV_CACHE_DEFAULT_COLD_MAX_TOKENS 30000
35	/* Tokenizers may merge text across the prompt boundary. Trimming a small tail
36	 * still improves the cheap token-prefix path, while text-prefix lookup handles
37	 * cases where canonical prompt tokenization spells the same bytes differently.
38	 * The 2048 alignment also matches the backend prefill chunk schedule, which
39	 * keeps compressor row finalization identical to a cold full prompt. */
40	#define KV_CACHE_DEFAULT_BOUNDARY_TRIM_TOKENS 32
41	#define KV_CACHE_DEFAULT_BOUNDARY_ALIGN_TOKENS 2048
42	#define KV_CACHE_DEFAULT_CONTINUED_INTERVAL_TOKENS 10000
43	/* Disk-hit counts are evidence that a checkpoint was useful, but only while
44	 * the workload still resembles the one that produced those hits. */
45	#define KV_CACHE_MIN_EFFECTIVE_HITS 0.01
46	/* A continued checkpoint that is a strict prefix of the incoming store is a
47	 * routine waypoint on the same path. Keep recent hits meaningful, but make
48	 * never-hit or stale waypoints cheap victims while pre-evicting for the new
49	 * store. */
50	#define KV_CACHE_CONTINUED_PREFIX_MIN_FACTOR 0.05
51	#define KV_CACHE_CONTINUED_PREFIX_HIT_FACTOR 0.45
52	/* Cold/evict/shutdown checkpoints are intentional anchors, not just automatic
53	 * waypoints in a single growing conversation. Give them a soft prior so they
54	 * survive comparable continued entries, while still allowing pressure and poor
55	 * density to evict them. */
56	#define KV_CACHE_ANCHOR_REASON_SCORE_FACTOR 2.0
57	
58	typedef struct {
59	    char *ptr;
60	    size_t len;
61	    size_t cap;
62	} kv_buf;
63	
64	static void kv_die(const char *msg) {
65	    fprintf(stderr, "ds4-kvstore: %s\n", msg);
66	    exit(1);
67	}
68	
69	static void *kv_xmalloc(size_t n) {
70	    void *p = malloc(n ? n : 1);
71	    if (!p) kv_die("out of memory");
72	    return p;
73	}
74	
75	static void *kv_xrealloc(void *p, size_t n) {
76	    p = realloc(p, n ? n : 1);
77	    if (!p) kv_die("out of memory");
78	    return p;
79	}
80	
81	static char *kv_xstrdup(const char *s) {
82	    size_t n = strlen(s);
83	    char *p = kv_xmalloc(n + 1);
84	    memcpy(p, s, n + 1);
85	    return p;
86	}
87	
88	static void kv_buf_reserve(kv_buf *b, size_t add) {
89	    if (add > SIZE_MAX - b->len - 1) kv_die("buffer overflow");
90	    size_t need = b->len + add + 1;
91	    if (need <= b->cap) return;
92	    size_t cap = b->cap ? b->cap * 2 : 256;
93	    while (cap < need) cap *= 2;
94	    b->ptr = kv_xrealloc(b->ptr, cap);
95	    b->cap = cap;
96	}
97	
98	static void kv_buf_append(kv_buf *b, const void *p, size_t n) {
99	    kv_buf_reserve(b, n);
100	    memcpy(b->ptr + b->len, p, n);
101	    b->len += n;
102	    b->ptr[b->len] = '\0';
103	}
104	
105	static void kv_buf_putc(kv_buf *b, char c) {
106	    kv_buf_append(b, &c, 1);
107	}
108	
109	static void kv_buf_puts(kv_buf *b, const char *s) {
110	    kv_buf_append(b, s, strlen(s));
111	}
112	
113	static void kv_buf_printf(kv_buf *b, const char *fmt, ...) {
114	    va_list ap;
