191	void ds4_kvstore_le_put32(uint8_t *p, uint32_t v) {
192	    p[0] = (uint8_t)v;
193	    p[1] = (uint8_t)(v >> 8);
194	    p[2] = (uint8_t)(v >> 16);
195	    p[3] = (uint8_t)(v >> 24);
196	}
197	
198	static void kv_le_put64(uint8_t *p, uint64_t v) {
199	    for (int i = 0; i < 8; i++) p[i] = (uint8_t)(v >> (8 * i));
200	}
201	
202	uint32_t ds4_kvstore_le_get32(const uint8_t *p) {
203	    return (uint32_t)p[0] |
204	           ((uint32_t)p[1] << 8) |
205	           ((uint32_t)p[2] << 16) |
206	           ((uint32_t)p[3] << 24);
207	}
208	
209	static uint64_t kv_le_get64(const uint8_t *p) {
210	    uint64_t v = 0;
211	    for (int i = 7; i >= 0; i--) v = (v << 8) | p[i];
212	    return v;
213	}
