215	typedef struct {
216	    uint32_t h[5];
217	    uint64_t bytes;
218	    uint8_t block[64];
219	    size_t used;
220	} sha1_ctx;
221	
222	static uint32_t rol32(uint32_t v, int n) {
223	    return (v << n) | (v >> (32 - n));
224	}
225	
226	static void sha1_transform(sha1_ctx *c, const uint8_t block[64]) {
227	    uint32_t w[80];
228	    for (int i = 0; i < 16; i++) {
229	        w[i] = ((uint32_t)block[i * 4] << 24) |
230	               ((uint32_t)block[i * 4 + 1] << 16) |
231	               ((uint32_t)block[i * 4 + 2] << 8) |
232	               (uint32_t)block[i * 4 + 3];
233	    }
234	    for (int i = 16; i < 80; i++)
235	        w[i] = rol32(w[i - 3] ^ w[i - 8] ^ w[i - 14] ^ w[i - 16], 1);
236	
237	    uint32_t a = c->h[0], b = c->h[1], d = c->h[3], e = c->h[4];
238	    uint32_t cc = c->h[2];
239	    for (int i = 0; i < 80; i++) {
240	        uint32_t f, k;
241	        if (i < 20) {
242	            f = (b & cc) | ((~b) & d);
243	            k = 0x5a827999u;
244	        } else if (i < 40) {
245	            f = b ^ cc ^ d;
246	            k = 0x6ed9eba1u;
247	        } else if (i < 60) {
248	            f = (b & cc) | (b & d) | (cc & d);
249	            k = 0x8f1bbcdcu;
250	        } else {
251	            f = b ^ cc ^ d;
252	            k = 0xca62c1d6u;
253	        }
254	        uint32_t tmp = rol32(a, 5) + f + e + k + w[i];
255	        e = d;
256	        d = cc;
257	        cc = rol32(b, 30);
258	        b = a;
259	        a = tmp;
260	    }
261	    c->h[0] += a;
262	    c->h[1] += b;
263	    c->h[2] += cc;
264	    c->h[3] += d;
265	    c->h[4] += e;
266	}
267	
268	static void sha1_init(sha1_ctx *c) {
269	    c->h[0] = 0x67452301u;
270	    c->h[1] = 0xefcdab89u;
271	    c->h[2] = 0x98badcfeu;
272	    c->h[3] = 0x10325476u;
273	    c->h[4] = 0xc3d2e1f0u;
274	    c->bytes = 0;
275	    c->used = 0;
276	}
277	
278	static void sha1_update(sha1_ctx *c, const void *ptr, size_t len) {
279	    const uint8_t *p = ptr;
280	    c->bytes += len;
281	    while (len != 0) {
282	        size_t n = 64 - c->used;
283	        if (n > len) n = len;
284	        memcpy(c->block + c->used, p, n);
285	        c->used += n;
286	        p += n;
287	        len -= n;
288	        if (c->used == 64) {
289	            sha1_transform(c, c->block);
290	            c->used = 0;
291	        }
292	    }
293	}
294	
295	static void sha1_final(sha1_ctx *c, uint8_t out[20]) {
296	    uint64_t bits = c->bytes * 8;
297	    uint8_t one = 0x80;
298	    uint8_t zero = 0;
299	    sha1_update(c, &one, 1);
300	    while (c->used != 56) sha1_update(c, &zero, 1);
301	    uint8_t len[8];
302	    for (int i = 0; i < 8; i++) len[7 - i] = (uint8_t)(bits >> (8 * i));
303	    sha1_update(c, len, sizeof(len));
304	    for (int i = 0; i < 5; i++) {
305	        out[i * 4] = (uint8_t)(c->h[i] >> 24);
306	        out[i * 4 + 1] = (uint8_t)(c->h[i] >> 16);
307	        out[i * 4 + 2] = (uint8_t)(c->h[i] >> 8);
308	        out[i * 4 + 3] = (uint8_t)c->h[i];
309	    }
310	}
311	
312	static void hex20(const uint8_t in[20], char out[41]) {
313	    static const char hex[] = "0123456789abcdef";
314	    for (int i = 0; i < 20; i++) {
315	        out[i * 2] = hex[in[i] >> 4];
316	        out[i * 2 + 1] = hex[in[i] & 15];
317	    }
318	    out[40] = '\0';
319	}
320	
321	void ds4_kvstore_sha1_bytes_hex(const void *ptr, size_t len, char out[41]) {
322	    sha1_ctx c;
323	    sha1_init(&c);
324	    sha1_update(&c, ptr, len);
325	    uint8_t digest[20];
326	    sha1_final(&c, digest);
327	    hex20(digest, out);
328	}
