393	void ds4_kvstore_fill_header(uint8_t h[DS4_KVSTORE_FIXED_HEADER],
394	                             uint8_t model_id, uint8_t quant_bits,
395	                             uint8_t reason, uint8_t ext_flags,
396	                             uint32_t tokens, uint32_t hits, uint32_t ctx_size,
397	                             uint64_t created_at, uint64_t last_used,
398	                             uint64_t payload_bytes) {
399	    memset(h, 0, DS4_KVSTORE_FIXED_HEADER);
400	    h[0] = KV_CACHE_MAGIC0;
401	    h[1] = KV_CACHE_MAGIC1;
402	    h[2] = KV_CACHE_MAGIC2;
403	    h[3] = KV_CACHE_VERSION;
404	    h[4] = quant_bits;
405	    h[5] = reason;
406	    h[6] = ext_flags;
407	    h[7] = model_id;
408	    ds4_kvstore_le_put32(h + 8, tokens);
409	    ds4_kvstore_le_put32(h + 12, hits);
410	    ds4_kvstore_le_put32(h + 16, ctx_size);
411	    h[20] = KV_CACHE_PAYLOAD_ABI;
412	    kv_le_put64(h + 24, created_at);
413	    kv_le_put64(h + 32, last_used);
414	    kv_le_put64(h + 40, payload_bytes);
415	}
416	
417	bool ds4_kvstore_read_header(FILE *fp, ds4_kvstore_entry *e,
418	                             uint32_t *text_bytes) {
419	    uint8_t h[DS4_KVSTORE_FIXED_HEADER];
420	    if (fread(h, 1, sizeof(h), fp) != sizeof(h)) return false;
421	    if (h[0] != KV_CACHE_MAGIC0 || h[1] != KV_CACHE_MAGIC1 ||
422	        h[2] != KV_CACHE_MAGIC2 || h[3] != KV_CACHE_VERSION) return false;
423	    if (h[20] != KV_CACHE_PAYLOAD_ABI) return false;
424	    e->quant_bits = h[4];
425	    e->reason = h[5] <= DS4_KVSTORE_REASON_AGENT_SESSION ? h[5] :
426	                DS4_KVSTORE_REASON_UNKNOWN;
427	    e->ext_flags = h[6];
428	    e->model_id = h[7];
429	    e->tokens = ds4_kvstore_le_get32(h + 8);
430	    e->hits = ds4_kvstore_le_get32(h + 12);
431	    e->ctx_size = ds4_kvstore_le_get32(h + 16);
432	    e->created_at = kv_le_get64(h + 24);
433	    e->last_used = kv_le_get64(h + 32);
434	    e->payload_bytes = kv_le_get64(h + 40);
435	    uint8_t tb[4];
436	    if (fread(tb, 1, sizeof(tb), fp) != sizeof(tb)) return false;
437	    *text_bytes = ds4_kvstore_le_get32(tb);
438	    e->text_bytes = *text_bytes;
439	    return e->tokens != 0 && (e->quant_bits == 2 || e->quant_bits == 4);
440	}
