442	bool ds4_kvstore_read_entry_file(const char *path, const char sha[41],
443	                                 ds4_kvstore_entry *out) {
444	    struct stat st;
445	    if (stat(path, &st) != 0 ||
446	        st.st_size < (off_t)(DS4_KVSTORE_FIXED_HEADER + 4))
447	        return false;
448	    FILE *fp = fopen(path, "rb");
449	    if (!fp) return false;
450	    ds4_kvstore_entry e = {0};
451	    uint32_t text_bytes = 0;
452	    bool ok = ds4_kvstore_read_header(fp, &e, &text_bytes);
453	    fclose(fp);
454	    if (!ok) return false;
455	    const uint64_t fixed = DS4_KVSTORE_FIXED_HEADER + 4ull;
456	    if (UINT64_MAX - fixed < (uint64_t)text_bytes ||
457	        UINT64_MAX - fixed - (uint64_t)text_bytes < e.payload_bytes)
458	        return false;
459	    const uint64_t expected = fixed + (uint64_t)text_bytes + e.payload_bytes;
460	    if ((uint64_t)st.st_size < expected) return false;
461	    memcpy(e.sha, sha, 41);
462	    e.path = kv_xstrdup(path);
463	    e.file_size = (uint64_t)st.st_size;
464	    *out = e;
465	    return true;
466	}
