468	static void kv_cache_refresh(ds4_kvstore *kc) {
469	    if (!kc->enabled) return;
470	    ds4_kvstore_clear(kc);
471	    DIR *d = opendir(kc->dir);
472	    if (!d) return;
473	    struct dirent *de;
474	    while ((de = readdir(d)) != NULL) {
475	        char sha[41];
476	        if (!ds4_kvstore_sha_hex_name(de->d_name, sha)) continue;
477	        char *path = ds4_kvstore_path_join(kc->dir, de->d_name);
478	        ds4_kvstore_entry e = {0};
479	        if (ds4_kvstore_read_entry_file(path, sha, &e)) kv_cache_push(kc, e);
480	        free(path);
481	    }
482	    closedir(d);
483	}
