485	bool ds4_kvstore_touch_file(const char *path, uint32_t hits) {
486	    FILE *fp = fopen(path, "r+b");
487	    if (!fp) return false;
488	    ds4_kvstore_entry e = {0};
489	    uint32_t text_bytes = 0;
490	    bool ok = ds4_kvstore_read_header(fp, &e, &text_bytes);
491	    if (ok) {
492	        uint8_t h[DS4_KVSTORE_FIXED_HEADER];
493	        uint64_t now = (uint64_t)time(NULL);
494	        ds4_kvstore_fill_header(h, e.model_id, e.quant_bits, e.reason, e.ext_flags,
495	                                e.tokens, hits, e.ctx_size,
496	                                e.created_at, now, e.payload_bytes);
497	        ok = fseek(fp, 0, SEEK_SET) == 0 &&
498	             fwrite(h, 1, sizeof(h), fp) == sizeof(h);
499	    }
500	    fclose(fp);
501	    return ok;
502	}
