504	static bool kv_cache_incoming_supersedes_continued(
505	        const ds4_kvstore_entry *e,
506	        const ds4_kvstore_eviction_context *incoming) {
507	    if (!e || !incoming || !incoming->text) return false;
508	    if (e->reason != DS4_KVSTORE_REASON_CONTINUED) return false;
509	    if (e->text_bytes == 0 || e->text_bytes > SIZE_MAX) return false;
510	    if ((size_t)e->text_bytes >= incoming->text_len) return false;
511	    if (e->model_id != incoming->model_id) return false;
512	    if (incoming->reject_different_quant &&
513	        e->quant_bits != incoming->quant_bits)
514	        return false;
515	    /* A smaller-context checkpoint can be loaded by a larger context, but not
516	     * the reverse.  The incoming checkpoint dominates this one only if it is at
517	     * least as widely reusable. */
518	    if (incoming->ctx_size > e->ctx_size) return false;
519	
520	    char prefix_sha[41];
521	    ds4_kvstore_sha1_bytes_hex(incoming->text, (size_t)e->text_bytes,
522	                               prefix_sha);
523	    return !strcmp(prefix_sha, e->sha);
524	}
