526	static bool kv_cache_reason_is_anchor(uint8_t reason) {
527	    return reason == DS4_KVSTORE_REASON_COLD ||
528	           reason == DS4_KVSTORE_REASON_EVICT ||
529	           reason == DS4_KVSTORE_REASON_SHUTDOWN;
530	}
531	
532	double ds4_kvstore_entry_eviction_score(
533	        const ds4_kvstore_entry *e,
534	        const ds4_tokens *live,
535	        uint64_t now,
536	        const ds4_kvstore_eviction_context *incoming) {
537	    if (!e || e->file_size == 0) return 0.0;
538	    (void)live;
539	    double effective_hits = (double)e->hits;
540	    uint64_t used_at = e->last_used ? e->last_used : e->created_at;
541	    if (used_at == 0) {
542	        effective_hits = 0.0;
543	    } else if (now > used_at) {
544	        double elapsed = (double)(now - used_at);
545	        effective_hits *= exp2(-elapsed / (double)DS4_KVSTORE_HIT_HALF_LIFE_SECONDS);
546	        if (effective_hits < KV_CACHE_MIN_EFFECTIVE_HITS) effective_hits = 0.0;
547	    }
548	    double score = (effective_hits + 1.0) *
549	                   (double)e->tokens / (double)e->file_size;
550	    if (kv_cache_reason_is_anchor(e->reason))
551	        score *= KV_CACHE_ANCHOR_REASON_SCORE_FACTOR;
552	    if (kv_cache_incoming_supersedes_continued(e, incoming)) {
553	        double h = effective_hits > 0.0 ?
554	            effective_hits / (effective_hits + 1.0) : 0.0;
555	        score *= KV_CACHE_CONTINUED_PREFIX_MIN_FACTOR +
556	                 KV_CACHE_CONTINUED_PREFIX_HIT_FACTOR * h;
557	    }
558	    return score;
559	}
560	
561	void ds4_kvstore_evict(ds4_kvstore *kc, const ds4_tokens *live,
562	                       uint64_t extra_bytes,
563	                       const ds4_kvstore_eviction_context *incoming) {
564	    if (!kc->enabled || kc->budget_bytes == 0) return;
565	    if (extra_bytes > kc->budget_bytes) return;
566	    kv_cache_refresh(kc);
567	    const uint64_t now = (uint64_t)time(NULL);
568	    uint64_t total = 0;
569	    for (int i = 0; i < kc->len; i++) total += kc->entry[i].file_size;
570	    const uint64_t target = kc->budget_bytes - extra_bytes;
571	    while (total > target && kc->len > 0) {
572	        int victim = 0;
573	        double victim_score =
574	            ds4_kvstore_entry_eviction_score(&kc->entry[0], live, now,
575	                                             incoming);
576	        for (int i = 1; i < kc->len; i++) {
577	            double score =
578	                ds4_kvstore_entry_eviction_score(&kc->entry[i], live, now,
579	                                                 incoming);
580	            if (score < victim_score ||
581	                (score == victim_score &&
582	                 kc->entry[i].last_used < kc->entry[victim].last_used))
583	            {
584	                victim = i;
585	                victim_score = score;
586	            }
587	        }
588	        ds4_kvstore_entry e = kc->entry[victim];
589	        if (unlink(e.path) == 0) {
590	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
591	                    "%s: kv cache evicted reason=disk-cache-full tokens=%u hits=%u size=%.2f MiB file=%s",
592	                    kv_log_name(kc),
593	                    e.tokens,
594	                    e.hits,
595	                    (double)e.file_size / (1024.0 * 1024.0),
596	                    e.path ? e.path : "?");
597	            if (total >= e.file_size) total -= e.file_size;
598	            else total = 0;
599	        } else {
600	            total = 0;
601	        }
602	        ds4_kvstore_entry_free(&e);
603	        memmove(kc->entry + victim, kc->entry + victim + 1,
604	                (size_t)(kc->len - victim - 1) * sizeof(kc->entry[0]));
605	        kc->len--;
606	    }
607	}
