609	bool ds4_kvstore_open(ds4_kvstore *kc, const char *dir, uint64_t budget_mb,
610	                      bool reject_different_quant, ds4_kvstore_options opt,
611	                      const char *log_name,
612	                      void (*log)(void *ud, ds4_kvstore_log_type type, const char *msg),
613	                      void *log_ud) {
614	    memset(kc, 0, sizeof(*kc));
615	    if (!dir) return false;
616	    kc->log_name = log_name;
617	    kc->log = log;
618	    kc->log_ud = log_ud;
619	    if (!kv_mkdir_p(dir)) {
620	        kv_logf(kc, DS4_KVSTORE_LOG_DEFAULT,
621	                "%s: failed to create KV cache directory %s: %s",
622	                kv_log_name(kc), dir, strerror(errno));
623	        return false;
624	    }
625	    kc->enabled = true;
626	    kc->dir = kv_xstrdup(dir);
627	    if (budget_mb == 0) budget_mb = DS4_KVSTORE_DEFAULT_MB;
628	    kc->budget_bytes = budget_mb * 1024ull * 1024ull;
629	    kc->reject_different_quant = reject_different_quant;
630	    kc->opt = opt;
631	    ds4_kvstore_evict(kc, NULL, 0, NULL);
632	    kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
633	            "%s: KV disk cache %s (budget=%llu MiB, cross-quant=%s, min=%d, cold_max=%d, continued=%d, trim=%d, align=%d, hit_half_life=%llus)",
634	            kv_log_name(kc),
635	            kc->dir,
636	            (unsigned long long)(kc->budget_bytes / (1024ull * 1024ull)),
637	            reject_different_quant ? "reject" : "accept",
638	            kc->opt.min_tokens,
639	            kc->opt.cold_max_tokens,
640	            kc->opt.continued_interval_tokens,
641	            kc->opt.boundary_trim_tokens,
642	            kc->opt.boundary_align_tokens,
643	            (unsigned long long)DS4_KVSTORE_HIT_HALF_LIFE_SECONDS);
644	    return true;
645	}
