653	char *ds4_kvstore_render_tokens_text(ds4_engine *engine,
654	                                     const ds4_tokens *tokens,
655	                                     size_t *out_len) {
656	    kv_buf b = {0};
657	    for (int i = 0; i < tokens->len; i++) {
