685	void ds4_kvstore_build_prompt_from_exact_prefix_and_text_suffix(
686	        ds4_engine *engine,
687	        const ds4_tokens *exact_prefix,
688	        const char *suffix_text,
689	        ds4_tokens *out) {
690	    ds4_tokens_copy(out, exact_prefix);
691	
692	    ds4_tokens suffix = {0};
693	    /* The suffix may start with DS4 chat markers such as <｜User｜> or
694	     * </think>, so use the rendered-chat tokenizer, not plain text BPE. */
695	    ds4_tokenize_rendered_chat(engine, suffix_text ? suffix_text : "", &suffix);
