700	int ds4_kvstore_store_len(const ds4_kvstore *kc, int tokens) {
701	    const int trim = kc->opt.boundary_trim_tokens;
702	    const int align = kc->opt.boundary_align_tokens;
703	    if (tokens > kc->opt.min_tokens + trim) {
704	        int stable = tokens - trim;
705	        if (align > 0) stable -= stable % align;
706	        if (stable >= kc->opt.min_tokens) return stable;
707	    }
708	    return tokens;
709	}
