711	int ds4_kvstore_chat_anchor_pos(const ds4_kvstore *kc,
712	                                const ds4_tokens *prompt,
713	                                int user_token_id,
714	                                int assistant_token_id) {
715	    if (!prompt || user_token_id < 0 || assistant_token_id < 0) return -1;
716	
717	    /* Cold checkpoints maximize reuse across independent agent sessions.  The
718	     * stable rendered chat prefix is everything before the user message that
719	     * asks this specific task.  Some clients put stable user-role scaffolding
720	     * first, so use the last user marker before the first assistant marker. */
721	    int last_user = -1;
722	    for (int i = 0; i < prompt->len; i++) {
723	        const int token = prompt->v[i];
724	        if (token == assistant_token_id) break;
725	        if (token == user_token_id) last_user = i;
726	    }
727	    return last_user >= kc->opt.min_tokens ? last_user : -1;
728	}
