730	static int kv_cache_continued_step(const ds4_kvstore *kc) {
731	    if (!kc->enabled || kc->opt.continued_interval_tokens <= 0) return 0;
732	    int step = kc->opt.continued_interval_tokens;
733	    const int align = kc->opt.boundary_align_tokens;
734	    if (align > 0) {
735	        step = ((step + align - 1) / align) * align;
736	        if (step <= 0) step = align;
737	    }
738	    return step;
739	}
740	
741	int ds4_kvstore_continued_store_target(const ds4_kvstore *kc, int live_tokens) {
742	    const int step = kv_cache_continued_step(kc);
743	    if (step <= 0) return 0;
744	    if (live_tokens < kc->opt.min_tokens) return 0;
745	    if (live_tokens % step != 0) return 0;
746	    if (live_tokens <= kc->continued_last_store_tokens) return 0;
747	    return live_tokens;
748	}
