750	void ds4_kvstore_note_store(ds4_kvstore *kc, int tokens) {
751	    if (tokens > kc->continued_last_store_tokens) {
752	        kc->continued_last_store_tokens = tokens;
753	    }
754	}
755	
756	int ds4_kvstore_suppress_continued_store(ds4_kvstore *kc, int tokens) {
757	    if (ds4_kvstore_continued_store_target(kc, tokens) != tokens) return -1;
758	    int old = kc->continued_last_store_tokens;
759	    ds4_kvstore_note_store(kc, tokens);
760	    return old;
761	}
