771	static bool kv_cache_file_size_bytes(uint64_t text_bytes,
772	                                     uint64_t payload_bytes,
773	                                     uint64_t trailer_bytes,
774	                                     uint64_t *file_bytes) {
775	    const uint64_t fixed = DS4_KVSTORE_FIXED_HEADER + 4ull;
776	    if (UINT64_MAX - fixed < text_bytes ||
777	        UINT64_MAX - fixed - text_bytes < payload_bytes ||
778	        UINT64_MAX - fixed - text_bytes - payload_bytes < trailer_bytes)
779	        return false;
780	    if (file_bytes) *file_bytes = fixed + text_bytes + payload_bytes + trailer_bytes;
781	    return true;
782	}
783	
784	static bool kv_cache_budget_required(uint64_t file_bytes,
785	                                     uint64_t *required_bytes) {
786	    /* The serialized size is deterministic for one snapshot, including the
787	     * optional trailer.  Reserve 1% headroom so filesystem/accounting surprises
788	     * cannot produce a file that is immediately removed by the budget pass. */
789	    uint64_t slack = file_bytes / 100u;
790	    if (file_bytes % 100u) slack++;
791	    if (UINT64_MAX - file_bytes < slack) return false;
792	    if (required_bytes) *required_bytes = file_bytes + slack;
793	    return true;
794	}
795	
796	bool ds4_kvstore_file_size_fits(const ds4_kvstore *kc,
797	                                uint64_t text_bytes,
798	                                uint64_t payload_bytes,
799	                                uint64_t trailer_bytes,
800	                                uint64_t *file_bytes_out,
801	                                uint64_t *required_bytes_out) {
802	    uint64_t file_bytes = 0;
803	    if (!kv_cache_file_size_bytes(text_bytes, payload_bytes, trailer_bytes,
804	                                  &file_bytes))
805	        return false;
806	    if (file_bytes_out) *file_bytes_out = file_bytes;
807	    if (!kc || kc->budget_bytes == 0) return true;
808	    uint64_t required = 0;
809	    if (!kv_cache_budget_required(file_bytes, &required)) return false;
810	    if (required_bytes_out) *required_bytes_out = required;
811	    return required <= kc->budget_bytes;
812	}
813	
814	static bool kv_cache_file_text_matches(const char *path, const char sha[41],
815	                                       const char *text, size_t text_len) {
816	    if (text_len > UINT32_MAX) return false;
817	    FILE *fp = fopen(path, "rb");
818	    if (!fp) return false;
819	
820	    ds4_kvstore_entry hdr = {0};
821	    uint32_t text_bytes = 0;
822	    bool ok = ds4_kvstore_read_header(fp, &hdr, &text_bytes) &&
823	              text_bytes == (uint32_t)text_len;
824	    char *stored = NULL;
825	    if (ok) {
826	        stored = kv_xmalloc((size_t)text_bytes + 1);
827	        ok = fread(stored, 1, text_bytes, fp) == text_bytes;
828	    }
829	    fclose(fp);
830	    if (!ok) {
831	        free(stored);
832	        return false;
833	    }
834	
835	    char stored_sha[41];
836	    ds4_kvstore_sha1_bytes_hex(stored, text_bytes, stored_sha);
837	    ok = !strcmp(stored_sha, sha) &&
838	         (text_len == 0 || memcmp(stored, text, text_len) == 0);
839	    free(stored);
840	    return ok;
841	}
842	
843	static bool kv_cache_existing_compatible(ds4_kvstore *kc, const char *path,
844	                                         const char sha[41],
845	                                         const char *text, size_t text_len,
846	                                         int model_id, int quant_bits, int ctx_size) {
847	    if (access(path, F_OK) != 0) return false;
848	    ds4_kvstore_entry e = {0};
849	    if (!ds4_kvstore_read_entry_file(path, sha, &e)) return false;
850	    bool compatible = e.model_id == (uint8_t)model_id &&
851	                      (!kc->reject_different_quant ||
852	                       e.quant_bits == (uint8_t)quant_bits) &&
853	                      e.ctx_size <= (uint32_t)ctx_size &&
854	                      kv_cache_file_text_matches(path, sha, text, text_len);
855	    ds4_kvstore_entry_free(&e);
856	    if (!compatible) {
857	        if (unlink(path) == 0) {
858	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
859	                    "%s: kv cache replaced incompatible file %s",
860	                    kv_log_name(kc), path);
861	        }
862	        return false;
863	    }
864	    return true;
865	}
866	
867	static bool kv_trailer_serialized_size(const ds4_kvstore_trailer_hooks *hooks,
868	                                       const char *text,
869	                                       uint64_t *bytes_out) {
870	    if (bytes_out) *bytes_out = 0;
871	    if (!hooks || !hooks->serialized_size) return true;
872	    return hooks->serialized_size(hooks->ud, text, bytes_out);
873	}
874	
875	static bool kv_trailer_write(const ds4_kvstore_trailer_hooks *hooks,
876	                             FILE *fp, const char *text,
877	                             uint64_t *written_bytes) {
878	    if (written_bytes) *written_bytes = 0;
879	    if (!hooks || !hooks->write) return true;
880	    return hooks->write(hooks->ud, fp, text, written_bytes);
881	}
882	
883	static void kv_cache_rewrite_trailer(ds4_kvstore *kc, const char *path,
884	                                     const char *text,
885	                                     const ds4_kvstore_trailer_hooks *hooks) {
886	    uint64_t trailer_est = 0;
887	    if (!hooks || !hooks->write || !hooks->serialized_size ||
888	        !kv_trailer_serialized_size(hooks, text, &trailer_est) ||
889	        trailer_est == 0)
890	    {
891	        return;
892	    }
893	    FILE *fp = fopen(path, "r+b");
894	    if (!fp) return;
895	    ds4_kvstore_entry hdr = {0};
896	    uint32_t text_bytes = 0;
897	    bool ok = ds4_kvstore_read_header(fp, &hdr, &text_bytes);
898	    uint64_t end = DS4_KVSTORE_FIXED_HEADER + 4ull +
899	                   (uint64_t)text_bytes + hdr.payload_bytes;
900	    if (ok && end <= (uint64_t)INT64_MAX &&
901	        fseeko(fp, (off_t)end, SEEK_SET) == 0 &&
902	        ftruncate(fileno(fp), (off_t)end) == 0)
903	    {
904	        uint64_t ignored = 0;
905	        ok = kv_trailer_write(hooks, fp, text, &ignored) && fflush(fp) == 0;
906	        if (ok && ignored > 0) {
907	            uint8_t h[DS4_KVSTORE_FIXED_HEADER];
908	            uint64_t now = (uint64_t)time(NULL);
909	            ds4_kvstore_fill_header(h, hdr.model_id, hdr.quant_bits, hdr.reason,
910	                                    (uint8_t)(hdr.ext_flags | hooks->ext_flag),
911	                                    hdr.tokens, hdr.hits, hdr.ctx_size,
912	                                    hdr.created_at, now, hdr.payload_bytes);
913	            ok = fseeko(fp, 0, SEEK_SET) == 0 &&
914	                 fwrite(h, 1, sizeof(h), fp) == sizeof(h) &&
915	                 fflush(fp) == 0;
916	        }
917	    }
918	    fclose(fp);
919	    (void)kc;
920	    (void)ok;
921	}
922	
923	bool ds4_kvstore_store_live_prefix_text(ds4_kvstore *kc,
924	                                        ds4_engine *engine,
925	                                        ds4_session *session,
926	                                        const ds4_tokens *tokens,
927	                                        int store_len,
928	                                        const char *reason,
929	                                        const char *cache_text_override,
930	                                        uint8_t cache_text_ext,
931	                                        const char *cache_text_key,
932	                                        const ds4_kvstore_trailer_hooks *hooks,
933	                                        char *err,
934	                                        size_t err_len) {
935	    if (!kc->enabled) return false;
936	    if (!tokens || store_len < kc->opt.min_tokens) return false;
937	    const int original_len = tokens->len;
938	
939	    ds4_tokens store_tokens = {0};
940	    ds4_kvstore_tokens_copy_prefix(&store_tokens, tokens, store_len);
941	
942	    const int quant_bits = ds4_engine_routed_quant_bits(engine);
943	    if (quant_bits != 2 && quant_bits != 4) {
944	        ds4_tokens_free(&store_tokens);
945	        return false;
946	    }
947	    const int model_id = ds4_engine_model_id(engine);
948	
949	    char save_err[160] = {0};
950	    const ds4_tokens *live_tokens = ds4_session_tokens(session);
951	    if (!live_tokens ||
952	        live_tokens->len != store_tokens.len ||
953	        !ds4_tokens_starts_with(live_tokens, &store_tokens))
954	    {
955	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
956	                "%s: kv cache skipped tokens=%d reason=%s because live checkpoint is at %d",
957	                kv_log_name(kc),
958	                store_tokens.len,
959	                reason,
960	                live_tokens ? live_tokens->len : -1);
961	        ds4_tokens_free(&store_tokens);
962	        return false;
963	    }
964	
965	    size_t text_len = 0;
966	    char *text = NULL;
967	    const bool text_override = cache_text_override && cache_text_override[0];
968	    if (text_override) {
969	        text = kv_xstrdup(cache_text_override);
970	        text_len = strlen(text);
971	    } else {
972	        text = ds4_kvstore_render_tokens_text(engine, &store_tokens, &text_len);
973	    }
974	    if (text_len > UINT32_MAX) {
975	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
976	                "%s: kv cache skipped tokens=%d because rendered text is too large",
977	                kv_log_name(kc), store_tokens.len);
978	        free(text);
979	        ds4_tokens_free(&store_tokens);
980	        return false;
981	    }
982	
983	    uint64_t trailer_est_bytes = 0;
984	    if (!kv_trailer_serialized_size(hooks, text, &trailer_est_bytes)) {
985	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
986	                "%s: kv cache skipped tokens=%d reason=%s because tool map size overflowed",
987	                kv_log_name(kc), store_tokens.len, reason);
988	        free(text);
989	        ds4_tokens_free(&store_tokens);
990	        return false;
991	    }
992	    char sha[41];
993	    ds4_kvstore_sha1_bytes_hex(text, text_len, sha);
994	    char *path = ds4_kvstore_path_for_sha(kc, sha);
995	    const uint8_t reason_code = ds4_kvstore_reason_code(reason);
996	
997	    if (kv_cache_existing_compatible(kc, path, sha, text, text_len,
998	                                     model_id,
999	                                     quant_bits, ds4_session_ctx(session))) {
1000	        kv_cache_rewrite_trailer(kc, path, text, hooks);
1001	        free(text);
1002	        free(path);
1003	        ds4_tokens_free(&store_tokens);
1004	        return true;
1005	    }
1006	
1007	    ds4_session_payload_file staged = {0};
1008	    if (ds4_session_stage_payload(session, &staged,
1009	                                  save_err, sizeof(save_err)) != 0) {
1010	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1011	                "%s: kv cache skipped tokens=%d reason=%s because KV payload staging failed: %s",
1012	                kv_log_name(kc),
1013	                store_tokens.len,
1014	                reason,
1015	                save_err[0] ? save_err : "unknown error");
1016	        if (err && err_len) snprintf(err, err_len, "%s",
1017	                                     save_err[0] ? save_err : "unknown error");
1018	        free(text);
1019	        free(path);
1020	        ds4_tokens_free(&store_tokens);
1021	        return false;
1022	    }
1023	    uint64_t payload_bytes = staged.bytes;
1024	
1025	    uint64_t est_file_bytes = 0, est_required_bytes = 0;
1026	    if (!ds4_kvstore_file_size_fits(kc, (uint64_t)text_len, payload_bytes,
1027	                                    trailer_est_bytes,
1028	                                    &est_file_bytes, &est_required_bytes)) {
1029	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1030	                "%s: kv cache skipped tokens=%d reason=%s because estimated file size %.2f MiB (%.2f MiB with safety) exceeds budget %.2f MiB",
1031	                kv_log_name(kc),
1032	                store_tokens.len,
1033	                reason,
1034	                (double)est_file_bytes / (1024.0 * 1024.0),
1035	                (double)est_required_bytes / (1024.0 * 1024.0),
1036	                (double)kc->budget_bytes / (1024.0 * 1024.0));
1037	        ds4_session_payload_file_free(&staged);
1038	        free(text);
1039	        free(path);
1040	        ds4_tokens_free(&store_tokens);
1041	        return false;
1042	    }
1043	
1044	    ds4_kvstore_eviction_context incoming = {
1045	        .text = text,
1046	        .text_len = text_len,
1047	        .model_id = (uint8_t)model_id,
1048	        .quant_bits = (uint8_t)quant_bits,
1049	        .ctx_size = (uint32_t)ds4_session_ctx(session),
1050	        .reject_different_quant = kc->reject_different_quant,
1051	    };
1052	    ds4_kvstore_evict(kc, live_tokens, est_file_bytes, &incoming);
1053	
1054	    kv_buf tmpb = {0};
1055	    kv_buf_printf(&tmpb, "%s.tmp.%ld", path, (long)getpid());
1056	    char *tmp = kv_buf_take(&tmpb);
1057	    const double save_t0 = kv_now_sec();
1058	    FILE *fp = fopen(tmp, "wb");
1059	    if (!fp) {
1060	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1061	                "%s: kv cache failed to create %s: %s save=%.1f ms",
1062	                kv_log_name(kc), tmp, strerror(errno),
1063	                (kv_now_sec() - save_t0) * 1000.0);
1064	        ds4_session_payload_file_free(&staged);
1065	        free(tmp);
1066	        free(text);
1067	        free(path);
1068	        ds4_tokens_free(&store_tokens);
1069	        return false;
1070	    }
1071	
1072	    const uint64_t now = (uint64_t)time(NULL);
1073	    uint8_t h[DS4_KVSTORE_FIXED_HEADER];
1074	    uint8_t ext_flags = trailer_est_bytes > 0 && hooks ? hooks->ext_flag : 0;
1075	    if (text_override) ext_flags |= cache_text_ext;
1076	    ds4_kvstore_fill_header(h, (uint8_t)model_id, (uint8_t)quant_bits,
1077	                            reason_code, ext_flags,
1078	                            (uint32_t)store_tokens.len, 0,
1079	                            (uint32_t)ds4_session_ctx(session),
1080	                            now, now, payload_bytes);
1081	    uint8_t tb[4];
1082	    ds4_kvstore_le_put32(tb, (uint32_t)text_len);
1083	    uint64_t trailer_bytes = 0;
1084	    errno = 0;
1085	    bool ok = fwrite(h, 1, sizeof(h), fp) == sizeof(h) &&
1086	              fwrite(tb, 1, sizeof(tb), fp) == sizeof(tb) &&
1087	              fwrite(text, 1, text_len, fp) == text_len &&
1088	              ds4_session_write_staged_payload(&staged, fp,
1089	                                               save_err, sizeof(save_err)) == 0 &&
1090	              kv_trailer_write(hooks, fp, text, &trailer_bytes) &&
1091	              fflush(fp) == 0;
1092	    int saved_errno = errno;
1093	    if (fclose(fp) != 0) {
1094	        if (!saved_errno) saved_errno = errno;
1095	        ok = false;
1096	    }
1097	    uint64_t final_file_bytes = 0, final_required_bytes = 0;
1098	    bool final_size_over_budget = false;
1099	    if (ok && !ds4_kvstore_file_size_fits(kc, (uint64_t)text_len, payload_bytes,
1100	                                          trailer_bytes,
1101	                                          &final_file_bytes,
1102	                                          &final_required_bytes))
1103	    {
1104	        final_size_over_budget = true;
1105	        ok = false;
1106	    }
1107	    if (ok && rename(tmp, path) != 0) {
1108	        saved_errno = errno;
1109	        ok = false;
1110	    }
1111	    const double save_ms = (kv_now_sec() - save_t0) * 1000.0;
1112	    if (!ok) {
1113	        if (final_size_over_budget) {
1114	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1115	                    "%s: kv cache skipped tokens=%d reason=%s because final file size %.2f MiB (%.2f MiB with safety) exceeds budget %.2f MiB save=%.1f ms",
1116	                    kv_log_name(kc),
1117	                    store_tokens.len,
1118	                    reason,
1119	                    (double)final_file_bytes / (1024.0 * 1024.0),
1120	                    (double)final_required_bytes / (1024.0 * 1024.0),
1121	                    (double)kc->budget_bytes / (1024.0 * 1024.0),
1122	                    save_ms);
1123	        } else {
1124	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1125	                    "%s: kv cache store failed (%s): %s save=%.1f ms",
1126	                    kv_log_name(kc),
1127	                    reason,
1128	                    saved_errno ? strerror(saved_errno) :
1129	                    (save_err[0] ? save_err : "unknown error"),
1130	                    save_ms);
1131	        }
1132	        if (err && err_len) {
1133	            snprintf(err, err_len, "%s",
1134	                     saved_errno ? strerror(saved_errno) :
1135	                     (save_err[0] ? save_err : "unknown error"));
1136	        }
1137	        unlink(tmp);
1138	    } else {
1139	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1140	                "%s: kv cache stored tokens=%d trimmed=%d reason=%s key=%s size=%.2f MiB save=%.1f ms",
1141	                kv_log_name(kc),
1142	                store_tokens.len,
1143	                original_len - store_tokens.len,
1144	                reason,
1145	                text_override ? (cache_text_key ? cache_text_key : "visible-transcript") : "token-text",
1146	                (double)(DS4_KVSTORE_FIXED_HEADER + 4ull + text_len + payload_bytes + trailer_bytes) / (1024.0 * 1024.0),
1147	                save_ms);
1148	    }
1149	    ds4_session_payload_file_free(&staged);
1150	    free(tmp);
1151	    free(text);
1152	    free(path);
1153	    ds4_tokens_free(&store_tokens);
1154	    return ok;
1155	}
