1190	int ds4_kvstore_find_text_prefix(ds4_kvstore *kc, const char *prompt_text,
1191	                                 int model_id, int quant_bits, int ctx_size) {
1192	    if (!prompt_text) return -1;
1193	    const size_t prompt_bytes = strlen(prompt_text);
1194	    kv_cache_refresh(kc);
1195	    int best = -1;
1196	    for (int i = 0; i < kc->len; i++) {
1197	        ds4_kvstore_entry *e = &kc->entry[i];
1198	        if (e->text_bytes > prompt_bytes || e->text_bytes > SIZE_MAX) continue;
1199	        if ((int)e->tokens < kc->opt.min_tokens) continue;
1200	        if (e->model_id != (uint8_t)model_id) continue;
1201	        if ((uint32_t)ctx_size < e->ctx_size) continue;
1202	        if (kc->reject_different_quant && e->quant_bits != (uint8_t)quant_bits) continue;
1203	        if (best >= 0) {
1204	            ds4_kvstore_entry *b = &kc->entry[best];
1205	            if (e->text_bytes < b->text_bytes) continue;
1206	            if (e->text_bytes == b->text_bytes && e->tokens <= b->tokens) continue;
1207	        }
1208	        char sha[41];
1209	        ds4_kvstore_sha1_bytes_hex(prompt_text, (size_t)e->text_bytes, sha);
1210	        if (!strcmp(sha, e->sha)) best = i;
1211	    }
1212	    return best;
1213	}
