1215	int ds4_kvstore_try_load_text(ds4_kvstore *kc,
1216	                              ds4_engine *engine,
1217	                              ds4_session *session,
1218	                              const char *prompt_text,
1219	                              ds4_tokens *effective_prompt,
1220	                              ds4_kvstore_load_result *result,
1221	                              const ds4_kvstore_trailer_hooks *hooks,
1222	                              bool responses_protocol) {
1223	    if (result) memset(result, 0, sizeof(*result));
1224	    if (effective_prompt) effective_prompt->len = 0;
1225	    if (!kc->enabled || !prompt_text) return 0;
1226	    const int quant_bits = ds4_engine_routed_quant_bits(engine);
1227	    if (quant_bits != 2 && quant_bits != 4) return 0;
1228	    const int model_id = ds4_engine_model_id(engine);
1229	    const size_t prompt_bytes = strlen(prompt_text);
1230	    int idx = ds4_kvstore_find_text_prefix(kc, prompt_text, model_id, quant_bits,
1231	                                           ds4_session_ctx(session));
1232	    if (idx < 0) return 0;
1233	
1234	    ds4_kvstore_entry e = kc->entry[idx];
1235	    char *path = kv_xstrdup(e.path);
1236	    const double load_t0 = kv_now_sec();
1237	    FILE *fp = fopen(path, "rb");
1238	    if (!fp) {
1239	        free(path);
1240	        return 0;
1241	    }
1242	    uint32_t text_bytes = 0;
1243	    ds4_kvstore_entry hdr = {0};
1244	    const char *fail_reason = "invalid header";
1245	    bool header_ok = ds4_kvstore_read_header(fp, &hdr, &text_bytes);
1246	    char *cached_text = NULL;
1247	    if (header_ok) {
1248	        if (hdr.model_id != (uint8_t)model_id) {
1249	            header_ok = false;
1250	            fail_reason = "cached checkpoint was written for a different model";
1251	        } else if ((uint64_t)text_bytes > prompt_bytes) {
1252	            header_ok = false;
1253	            fail_reason = "cached text is longer than prompt";
1254	        } else {
1255	            cached_text = kv_xmalloc((size_t)text_bytes + 1);
1256	            if (fread(cached_text, 1, text_bytes, fp) != text_bytes) {
1257	                header_ok = false;
1258	                fail_reason = "truncated cached text";
1259	            } else {
1260	                cached_text[text_bytes] = '\0';
1261	                char text_sha[41];
1262	                ds4_kvstore_sha1_bytes_hex(cached_text, text_bytes, text_sha);
1263	                if (strcmp(text_sha, e.sha)) {
1264	                    header_ok = false;
1265	                    fail_reason = "cached text hash mismatch";
1266	                } else if (!ds4_kvstore_byte_prefix_match(prompt_text, prompt_bytes,
1267	                                                          cached_text, text_bytes)) {
1268	                    header_ok = false;
1269	                    fail_reason = "cached text prefix mismatch";
1270	                }
1271	            }
1272	        }
1273	    }
1274	    char err[160] = {0};
1275	    int loaded = 0;
1276	    if (header_ok &&
1277	        ds4_session_load_payload(session, fp, hdr.payload_bytes, err, sizeof(err)) == 0)
1278	    {
1279	        const ds4_tokens *loaded_tokens = ds4_session_tokens(session);
1280	        if (loaded_tokens && loaded_tokens->len == (int)hdr.tokens) {
1281	            loaded = (int)hdr.tokens;
1282	            if (effective_prompt) {
1283	                /* The cache lookup was by bytes, but the graph state is still
1284	                 * the exact token history stored in the payload.  Build the
1285	                 * prompt from that exact history and tokenize only the text
1286	                 * suffix after the byte prefix. */
1287	                ds4_kvstore_build_prompt_from_exact_prefix_and_text_suffix(
1288	                    engine, loaded_tokens, prompt_text + text_bytes,
1289	                    effective_prompt);
1290	            }
1291	            if (hooks && hooks->load && (hdr.ext_flags & hooks->ext_flag)) {
1292	                hooks->load(hooks->ud, fp, hooks->load_wanted);
1293	            }
1294	        } else {
1295	            ds4_session_invalidate(session);
1296	            unlink(path);
1297	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1298	                    "%s: kv cache discarded corrupt text-prefix payload%s%s %s",
1299	                    kv_log_name(kc),
1300	                    responses_protocol ? " " : "",
1301	                    responses_protocol ? "RESPPROTO" : "",
1302	                    path);
1303	        }
1304	    } else {
1305	        if (header_ok) ds4_session_invalidate(session);
1306	        kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1307	                "%s: kv cache load failed%s%s %s: %s load=%.1f ms",
1308	                kv_log_name(kc),
1309	                responses_protocol ? " " : "",
1310	                responses_protocol ? "RESPPROTO" : "",
1311	                path,
1312	                header_ok ? err : fail_reason,
1313	                (kv_now_sec() - load_t0) * 1000.0);
1314	    }
1315	    fclose(fp);
1316	
1317	    if (loaded > 0) {
1318	        const double load_ms = (kv_now_sec() - load_t0) * 1000.0;
1319	        kc->continued_last_store_tokens = loaded;
1320	        const char *key_kind = ds4_kvstore_key_kind(hdr.ext_flags);
1321	        bool consumed = false;
1322	        if (kc->opt.cold_max_tokens > 0 && loaded > kc->opt.cold_max_tokens) {
1323	            unlink(path);
1324	            consumed = true;
1325	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1326	                    "%s: kv cache hit text%s%s tokens=%d text=%u quant=%u key=%s load=%.1f ms consumed file=%s",
1327	                    kv_log_name(kc),
1328	                    responses_protocol ? " " : "",
1329	                    responses_protocol ? "RESPPROTO" : "",
1330	                    loaded, text_bytes, hdr.quant_bits, key_kind, load_ms, path);
1331	        } else {
1332	            ds4_kvstore_touch_file(path, hdr.hits + 1);
1333	            kv_logf(kc, DS4_KVSTORE_LOG_KVCACHE,
1334	                    "%s: kv cache hit text%s%s tokens=%d text=%u quant=%u key=%s load=%.1f ms file=%s",
1335	                    kv_log_name(kc),
1336	                    responses_protocol ? " " : "",
1337	                    responses_protocol ? "RESPPROTO" : "",
1338	                    loaded, text_bytes, hdr.quant_bits, key_kind, load_ms, path);
1339	        }
1340	        if (result) {
1341	            result->tokens = loaded;
1342	            result->text_bytes = text_bytes;
1343	            result->quant_bits = hdr.quant_bits;
1344	            result->ext_flags = hdr.ext_flags;
1345	            result->load_ms = load_ms;
1346	            result->consumed = consumed;
1347	            result->path = kv_xstrdup(path);
1348	        }
1349	    }
1350	    free(cached_text);
1351	    free(path);
1352	    return loaded;
1353	}
